const page = $input.first().json;
const prev = $('Initialize').first().json;

const staticData = $getWorkflowStaticData('global');

if (staticData.executionId !== $execution.id) {
  staticData.executionId = $execution.id;
  staticData.allLeads = [];
}

const newItems = page.items || [];
staticData.allLeads = staticData.allLeads.concat(newItems);

const nextCursor = page.next_starting_after || null;
const hasMore    = newItems.length === 100 && nextCursor !== null;

return [{
  json: {
    dateFrom:     prev.dateFrom,
    dateTo:       prev.dateTo,
    dateLabel:    prev.dateLabel,
    campaignId:   prev.campaignId,
    campaignName: prev.campaignName,
    dedupeField:  prev.dedupeField,
    nextCursor,
    hasMore,
    pageCount: Math.ceil(staticData.allLeads.length / 100)
  }
}];

const input = $input.first().json;

const staticData = $getWorkflowStaticData('global');
const allLeads   = staticData.allLeads || [];

const dateFrom    = new Date(input.dateFrom);
const dateTo      = new Date(input.dateTo);
const dedupeField = input.dedupeField || 'website';

function getDedupeKey(lead) {
  if (dedupeField === 'fullName') {
    return ((lead.payload && lead.payload['Full Name']) || '').trim().toLowerCase();
  }
  return (lead.website || '').trim().toLowerCase();
}

// Yesterday's leads and unique values
const filteredYesterday = allLeads.filter(lead => {
  if (!lead.timestamp_last_contact) return false;
  const ts = new Date(lead.timestamp_last_contact);
  return ts >= dateFrom && ts <= dateTo;
});

const seenYesterday = new Set();
for (const lead of filteredYesterday) {
  const key = getDedupeKey(lead);
  if (key) seenYesterday.add(key);
}

// All-time unique values (no date filter)
const seenAllTime = new Set();
for (const lead of allLeads) {
  const key = getDedupeKey(lead);
  if (key) seenAllTime.add(key);
}

// Clear static data after use
staticData.allLeads    = [];
staticData.executionId = null;

return [{
  json: {
    campaignId:         input.campaignId,
    campaignName:       input.campaignName,
    dateLabel:          input.dateLabel,
    dedupeField,
    totalLeads:         filteredYesterday.length,
    uniqueCount:        seenYesterday.size,
    allTimeUniqueCount: seenAllTime.size,
    totalFetched:       allLeads.length
  }
}];

const unique = $('Filter & Dedupe').first().json;

// All-time overview — no date filter, returns single object
const allTime = $('Fetch All-Time Analytics').first().json;

// Yesterday overview — date-filtered, returns single object
const yday = $('Fetch Yesterday Analytics').first().json;

function totalReplies(a) {
  // Unique manual replies + unique automatic replies
  return (a.reply_count_unique || 0) + (a.reply_count_automatic_unique || 0);
}
function replyRate(replies, uniqueLeads) {
  if (!uniqueLeads) return '0.00%';
  return (replies / uniqueLeads * 100).toFixed(2) + '%';
}
function positiveRate(positive, uniqueLeads) {
  if (!uniqueLeads) return '0.00%';
  return (positive / uniqueLeads * 100).toFixed(2) + '%';
}

return [{
  json: {
    campaignId:   unique.campaignId,
    campaignName: unique.campaignName,
    dateLabel:    unique.dateLabel,
    dedupeField:  unique.dedupeField,

    // Unique contacted counts (from leads pagination)
    totalLeads:         unique.totalLeads,
    uniqueCount:        unique.uniqueCount,
    allTimeUniqueCount: unique.allTimeUniqueCount,
    totalFetched:       unique.totalFetched,

    // Yesterday analytics
    yday_contacted:     yday.new_leads_contacted_count || 0,
    yday_replies:       totalReplies(yday),
    yday_positive:      yday.total_interested          || 0,
    yday_reply_rate:    replyRate(totalReplies(yday),            unique.uniqueCount),
    yday_positive_rate: positiveRate(yday.total_interested || 0, unique.uniqueCount),

    // All-time analytics
    alltime_contacted:     allTime.new_leads_contacted_count || 0,
    alltime_replies:       totalReplies(allTime),
    alltime_positive:      (allTime.total_interested || 0) + (unique.campaignId === 'cb5b45d3-67ce-46ce-bfe8-3e2e70bdd2f3' ? 2 : 0),
    alltime_reply_rate:    replyRate(totalReplies(allTime),            unique.allTimeUniqueCount),
    alltime_positive_rate: positiveRate((allTime.total_interested || 0) + (unique.campaignId === 'cb5b45d3-67ce-46ce-bfe8-3e2e70bdd2f3' ? 2 : 0), unique.allTimeUniqueCount),
  }
}];

const input = $input.first().json;

// Use America/New_York (EST/EDT) for all date calculations
const now       = $now.setZone('America/New_York');
const yesterday = now.minus({ days: 1 });

const yesterdayStart = yesterday.startOf('day');
const yesterdayEnd   = yesterday.endOf('day');

return [{
  json: {
    dateFrom:     yesterdayStart.toISO(),
    dateTo:       yesterdayEnd.toISO(),
    dateLabel:    yesterdayStart.toFormat('yyyy-MM-dd'),
    campaignId:   input.campaignId,
    campaignName: input.campaignName,
    dedupeField:  input.dedupeField || 'website',
    nextCursor:   null
  }
}];
